ALGORITHM Eisner
BEGIN
  for span in 1 to n:
    for i in 0 to n-span:
      j = i + span
      // Complete spans
      for k in i to j:
        INCOMPLETE[i][j] = max(INCOMPLETE[i][k] + COMPLETE[k][j])
      // Incomplete spans
      for k in i to j:
        COMPLETE[i][j] = max(COMPLETE[i][k] + INCOMPLETE[k][j])
END
